/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER trg_ritardo_insert
BEFORE INSERT ON presenze
FOR EACH ROW
BEGIN
  IF NEW.ora_entrata IS NOT NULL
     AND TIME(NEW.ora_entrata) > '08:15:00'
     AND NEW.stato = 'presente'
  THEN
    SET NEW.stato = 'ritardo';
  END IF;
END */;;
DELIMITER ;
