/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER trg_uscita_anticipata_update
BEFORE UPDATE ON presenze
FOR EACH ROW
BEGIN
  IF NEW.ora_uscita IS NOT NULL
     AND OLD.ora_uscita IS NULL
     AND TIME(NEW.ora_uscita) < '13:30:00'
  THEN
    SET NEW.stato = 'uscita_anticipata';
  END IF;
END */;;
DELIMITER ;
