/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER trg_cleanup_token_disattivazione
AFTER UPDATE ON utenti
FOR EACH ROW
BEGIN
  IF NEW.attivo = 0 AND OLD.attivo = 1 THEN
    DELETE FROM password_reset_tokens WHERE utente_id = NEW.id;
  END IF;
END */;;
